import{_ as e,c as d,o,a3 as a}from"./chunks/framework.CTM16EAR.js";const g=JSON.parse('{"title":"附录：术语对照表","description":"Activity、活动清单、Todo、Task 等中英文与层级关系的集中说明，便于对照文档与界面。","frontmatter":{"title":"附录：术语对照表","description":"Activity、活动清单、Todo、Task 等中英文与层级关系的集中说明，便于对照文档与界面。"},"headers":[],"relativePath":"guide/appendix/glossary.md","filePath":"guide/appendix/glossary.md","lastUpdated":1778035726000}'),r={name:"guide/appendix/glossary.md"};function c(i,t,h,n,s,l){return o(),d("div",null,t[0]||(t[0]=[a('<h1 id="附录-术语对照" tabindex="-1">附录：术语对照 <a class="header-anchor" href="#附录-术语对照" aria-label="Permalink to &quot;附录：术语对照&quot;">​</a></h1><p>本页把<strong>数据模型</strong>、<strong>界面分区</strong>与<strong>同步存储</strong>里常见的英文标识放在一起对照，避免把 <code>Activity</code>、<code>ActivitySheet</code>、<code>Todo</code>、<code>Task</code> 混为一谈。细节仍以各模块文档为准。</p><hr><h2 id="核心对照-activity-族" tabindex="-1">核心对照（Activity 族） <a class="header-anchor" href="#核心对照-activity-族" aria-label="Permalink to &quot;核心对照（Activity 族）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>中文（文档常用）</th><th>英文 / 代码标识</th><th>指什么</th><th>易混点</th></tr></thead><tbody><tr><td>活动（条目）</td><td><code>Activity</code></td><td>出现在活动清单中的一条记录；类型包括待办、预约、无所事事、内外打扰等。</td><td>不是「任务追踪」里的 Task；也不是整页应用。</td></tr><tr><td>活动清单 / 右侧面板</td><td><code>ActivitySheet</code>（组件）、<code>activitySheet</code>（存储键）</td><td><strong>界面</strong>：首页右侧管理活动的区域，由 <code>ActivitySheet</code> 组件实现。<br><strong>数据</strong>：本地/同步里常以键名 <code>activitySheet</code> 保存活动数组。</td><td>「Sheet」在代码里是组件名；用户文档里多称「活动清单」或「活动清单视图」。</td></tr><tr><td>待办（待办活动）</td><td><code>Todo</code></td><td><code>Activity</code> 的一种子类型：用番茄块拆分的可执行项（🍅/🍒/🍇）。</td><td>口语里的「待办任务」多指 <code>Todo</code>，但严格说仍是 <strong>Activity</strong>，不是下面的 <strong>Task</strong>。</td></tr><tr><td>任务（追踪任务）</td><td><code>Task</code></td><td><strong>任务追踪</strong>里当前选中的执行记录：描述、能量/愉悦/打扰等时间轴都挂在这里；通常由某个 <code>Activity</code>（含 <code>Todo</code>、<code>Schedule</code> 等）进入追踪后对应。</td><td>与 GTD 里泛指的「任务」不同：此处特指追踪视图中的那条<strong>执行记录</strong>。</td></tr></tbody></table><p>一句话串起来：<strong>清单里的一条是 <code>Activity</code>；其中一类待办是 <code>Todo</code>；你点「追踪」后在追踪区写的是 <code>Task</code>，往往绑定到某个 <code>Activity</code>。</strong></p><hr><h2 id="与「视图」相关的说法" tabindex="-1">与「视图」相关的说法 <a class="header-anchor" href="#与「视图」相关的说法" aria-label="Permalink to &quot;与「视图」相关的说法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>说法</th><th>含义</th></tr></thead><tbody><tr><td>活动清单视图</td><td>强调「看活动清单」这一视图状态；与任务计划、任务追踪等视图并列。</td></tr><tr><td>任务计划视图</td><td>按日/周/月查看与操作已排入计划的活动（今日待办、今日预约等）。见 <a href="./../reference/planner.html">任务规划</a>。</td></tr><tr><td>任务追踪视图</td><td>记录执行过程、能量、打扰等的区域。见 <a href="./../reference/task.html">任务追踪</a>。</td></tr></tbody></table><hr><h2 id="其他活动类型-同为-activity" tabindex="-1">其他活动类型（同为 <code>Activity</code>） <a class="header-anchor" href="#其他活动类型-同为-activity" aria-label="Permalink to &quot;其他活动类型（同为 `Activity`）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>中文</th><th>英文</th></tr></thead><tbody><tr><td>预约</td><td><code>Schedule</code></td></tr><tr><td>无所事事</td><td><code>Untaetigkeit</code>（文档用语）；数据上多为带 <code>isUntaetigkeit: true</code> 的 <code>Schedule</code> 分支</td></tr><tr><td>内部打扰 / 外部打扰</td><td><code>Internal Interruption</code> / <code>External Interruption</code></td></tr></tbody></table><p>完整图标与定义见 <a href="./../reference/activity.html">活动清单</a>。</p><hr><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="./../reference/activity.html">活动清单</a>（<code>Activity</code> / <code>Todo</code> / <code>Schedule</code> 等定义）</li><li><a href="./../reference/task.html">任务追踪</a>（<code>Task</code> 与各记录类型）</li><li><a href="./../reference/interface.html">软件界面</a>（各面板分工与联动）</li><li><a href="./buttons.html">附录：按钮一览</a>（工具栏图标与英文标签速查）</li></ul>',16)]))}const p=e(r,[["render",c]]);export{g as __pageData,p as default};
